
import pandas as pd
def label_count(df,family,label): return int(df[family].fillna('').astype(str).str.contains(label, regex=False).sum()) if family in df.columns else 0
def corpus_support(df,needed):
    counts={label:label_count(df,fam,label) for fam,label in needed}; present=sum(v>0 for v in counts.values()); repeated=sum(v>=3 for v in counts.values()); return min(5,max(1,present+(1 if repeated>=3 else 0))), counts
