def theme_pair_matrix(df,col_a,col_b):
    rows=[]
    for _,row in df.iterrows():
        a=[x.strip() for x in str(row.get(col_a,'')).split(';') if x.strip()]; b=[x.strip() for x in str(row.get(col_b,'')).split(';') if x.strip()]
        for x in a:
            for y in b: rows.append((x,y,row.get('title','')))
    if not rows: return pd.DataFrame(columns=[col_a,col_b,'count'])
    tmp=pd.DataFrame(rows,columns=[col_a,col_b,'title']); return tmp.groupby([col_a,col_b]).size().reset_index(name='count').sort_values('count', ascending=False)
